// Generated by @canonical/summon-component:react v0.1.0

import { createMemoryRouter } from "@canonical/router-core";
import { RouterProvider } from "@canonical/router-react";
import { fireEvent, render, screen, waitFor } from "@testing-library/react";
import { describe, expect, it } from "vitest";
import { appRoutes, notFoundRoute } from "../../routes.js";
import { LENS_ENTRIES } from "./constants.js";
import Rail from "./Rail.js";

/** Mount the rail under a real in-memory router over the app's route table. */
const renderRail = (initialUrl = "/") => {
  const router = createMemoryRouter(appRoutes, initialUrl, {
    notFound: notFoundRoute,
  });
  const view = render(
    <RouterProvider router={router}>
      <Rail />
    </RouterProvider>,
  );
  return { router, view };
};

describe("Rail", () => {
  it("is a labelled nav carrying the v1 lens set in the ruled order", () => {
    renderRail();
    const nav = screen.getByRole("navigation", { name: "Primary" });
    expect(nav.dataset.region).toBe("primary-nav");
    const labels = [...nav.querySelectorAll(".rail-lenses .rail-label")].map(
      (label) => label.textContent,
    );
    expect(labels).toEqual([
      "Home",
      "Components",
      "Definitions",
      "Standards",
      "Guides",
    ]);
  });

  it("shows each lens's keyboard hint as kbd and aria-keyshortcuts", () => {
    renderRail();
    for (const { label, hint } of LENS_ENTRIES) {
      const link = screen.getByRole("link", { name: label });
      expect(link).toHaveAttribute("aria-keyshortcuts", hint);
      expect(link.querySelector("kbd")?.textContent).toBe(hint);
    }
  });

  it("marks the active lens with the router's aria-current", () => {
    renderRail("/components");
    expect(screen.getByRole("link", { name: "Components" })).toHaveAttribute(
      "aria-current",
      "page",
    );
    expect(screen.getByRole("link", { name: "Standards" })).not.toHaveAttribute(
      "aria-current",
    );
  });

  it("keeps the utility cluster out of the lens list", () => {
    renderRail();
    const utilities = screen.getByRole("list", { name: "Utilities" });
    expect(
      utilities.contains(screen.getByRole("link", { name: "Playground" })),
    ).toBe(true);
    expect(
      utilities.contains(screen.getByRole("link", { name: "Demo sign-in" })),
    ).toBe(true);
    expect(
      utilities.contains(screen.getByRole("combobox", { name: "Color theme" })),
    ).toBe(true);
  });

  it("navigates on a bare lens digit (the wired keyboard grammar)", async () => {
    const { router } = renderRail("/");
    fireEvent.keyDown(document, { key: "2" });
    await waitFor(() => {
      expect(router.getState().location.pathname).toBe("/components");
    });
  });

  it("leaves digits alone while typing in an editable target", () => {
    const { router, view } = renderRail("/");
    const input = document.createElement("input");
    view.container.appendChild(input);
    fireEvent.keyDown(input, { key: "2" });
    expect(router.getState().location.pathname).toBe("/");
  });

  it("leaves modifier chords alone", () => {
    const { router } = renderRail("/");
    fireEvent.keyDown(document, { key: "2", ctrlKey: true });
    expect(router.getState().location.pathname).toBe("/");
  });

  it("detaches the listener on unmount (the ephemeral contract)", async () => {
    const { router, view } = renderRail("/");
    view.unmount();
    fireEvent.keyDown(document, { key: "3" });
    // Give a queued navigation a beat to (wrongly) land before asserting.
    await new Promise((resolve) => setTimeout(resolve, 20));
    expect(router.getState().location.pathname).toBe("/");
  });
});
